"""sklearn.utils — Utility helpers for validation and resampling."""
import numpy as np
from sklearn.exceptions import NotFittedError


def check_array(array, dtype=None, ensure_2d=True, allow_nd=False, copy=False):
    """Validate an array-like input and convert to numpy."""
    arr = np.array(array, dtype=dtype, copy=copy)
    if ensure_2d and arr.ndim == 1:
        arr = arr.reshape(-1, 1)
    if not allow_nd and arr.ndim > 2:
        raise ValueError("Found array with dim %d. Expected <= 2." % arr.ndim)
    return arr


def check_X_y(X, y, dtype=None, ensure_2d=True, allow_nd=False, multi_output=False):
    """Validate X and y, returning numpy arrays."""
    X = check_array(X, dtype=dtype, ensure_2d=ensure_2d, allow_nd=allow_nd)
    y = np.asarray(y)
    if X.shape[0] != y.shape[0]:
        raise ValueError("X and y have inconsistent number of samples: "
                         "%d vs %d" % (X.shape[0], y.shape[0]))
    return X, y


def check_is_fitted(estimator, attributes=None, msg=None):
    """Check that an estimator has been fitted."""
    if msg is None:
        msg = ("This %(name)s instance is not fitted yet. Call 'fit' first."
               % {'name': type(estimator).__name__})
    if attributes is not None:
        if isinstance(attributes, str):
            attributes = [attributes]
        for attr in attributes:
            if not hasattr(estimator, attr):
                raise NotFittedError(msg)
    else:
        # Check for any attribute ending with '_'
        fitted_attrs = [a for a in vars(estimator) if a.endswith('_') and not a.startswith('__')]
        if not fitted_attrs:
            raise NotFittedError(msg)


def resample(*arrays, replace=True, n_samples=None, random_state=None):
    """Resample arrays with or without replacement."""
    rng = np.random.RandomState(random_state) if isinstance(random_state, int) else np.random.RandomState()
    if len(arrays) == 0:
        return []
    n = arrays[0].shape[0] if hasattr(arrays[0], 'shape') else len(arrays[0])
    if n_samples is None:
        n_samples = n
    if replace:
        indices = rng.randint(0, n, size=n_samples)
    else:
        indices = rng.permutation(n)[:n_samples]
    results = []
    for a in arrays:
        a = np.asarray(a)
        results.append(a[indices])
    return results if len(results) > 1 else results[0]


def shuffle(*arrays, random_state=None):
    """Shuffle arrays consistently."""
    rng = np.random.RandomState(random_state) if isinstance(random_state, int) else np.random.RandomState()
    n = arrays[0].shape[0] if hasattr(arrays[0], 'shape') else len(arrays[0])
    indices = rng.permutation(n)
    results = [np.asarray(a)[indices] for a in arrays]
    return results if len(results) > 1 else results[0]


class Bunch(dict):
    """A dict that also allows attribute-style access."""
    def __init__(self, **kwargs):
        super().__init__(kwargs)
        self.__dict__ = self


# ---------------------------------------------------------------------------
# Extended check_array and check_X_y (overwrite simple stubs above with
# full-signature versions while keeping backward compatibility)
# ---------------------------------------------------------------------------

def check_array_full(array, accept_sparse=False, accept_large_sparse=True,
                     dtype='numeric', order=None, copy=False,
                     force_all_finite=True, ensure_2d=True, allow_nd=False,
                     ensure_min_samples=1, ensure_min_features=1,
                     estimator=None, input_name=''):
    """Validate an array-like input and convert to numpy (full signature)."""
    if dtype == 'numeric':
        dt = float
    elif dtype is None:
        dt = None
    else:
        dt = dtype
    arr = np.array(array, dtype=dt, copy=copy)
    if order is not None and order in ('C', 'F'):
        arr = np.asarray(arr, order=order)
    if ensure_2d and arr.ndim == 1:
        arr = arr.reshape(-1, 1)
    if not allow_nd and arr.ndim > 2:
        name = input_name or 'array'
        raise ValueError("Found %s with dim %d. Expected <= 2." % (name, arr.ndim))
    if force_all_finite:
        if np.any(np.isnan(arr)) or np.any(np.isinf(arr)):
            raise ValueError("Input contains NaN or infinity.")
    if ensure_2d or arr.ndim == 2:
        if arr.ndim >= 2 and arr.shape[0] < ensure_min_samples:
            raise ValueError("Found array with %d sample(s), while a minimum "
                             "of %d is required." % (arr.shape[0], ensure_min_samples))
        if arr.ndim >= 2 and arr.shape[1] < ensure_min_features:
            raise ValueError("Found array with %d feature(s), while a minimum "
                             "of %d is required." % (arr.shape[1], ensure_min_features))
    return arr


def check_X_y_full(X, y, accept_sparse=False, accept_large_sparse=True,
                   dtype='numeric', order=None, copy=False,
                   force_all_finite=True, ensure_2d=True, allow_nd=False,
                   multi_output=False, ensure_min_samples=1,
                   ensure_min_features=1, y_numeric=False, estimator=None):
    """Validate X and y, returning numpy arrays (full signature)."""
    X = check_array_full(X, accept_sparse=accept_sparse,
                         accept_large_sparse=accept_large_sparse,
                         dtype=dtype, order=order, copy=copy,
                         force_all_finite=force_all_finite,
                         ensure_2d=ensure_2d, allow_nd=allow_nd,
                         ensure_min_samples=ensure_min_samples,
                         ensure_min_features=ensure_min_features,
                         estimator=estimator)
    y_dt = float if y_numeric else None
    y = np.asarray(y, dtype=y_dt)
    if X.shape[0] != y.shape[0]:
        raise ValueError("X and y have inconsistent number of samples: "
                         "%d vs %d" % (X.shape[0], y.shape[0]))
    if not multi_output and y.ndim > 1 and y.shape[1] > 1:
        raise ValueError("y should be a 1d array or column vector. "
                         "Got shape %s." % str(y.shape))
    return X, y


# Replace module-level names so both simple and full-signature calls work
check_array = check_array_full
check_X_y = check_X_y_full


