def check_random_state(seed):
    """Turn seed into a np.random.RandomState instance.

    Parameters
    ----------
    seed : None, int, or np.random.RandomState
    """
    if seed is None or seed is np.random:
        return np.random.mtrand._rand
    if isinstance(seed, (int, np.integer)):
        return np.random.RandomState(seed)
    if isinstance(seed, np.random.RandomState):
        return seed
    raise ValueError("%r cannot be used to seed a RandomState instance" % seed)


def check_is_fitted_full(estimator, attributes=None, msg=None, all_or_any=all):
    """Raise NotFittedError if not fitted (full signature)."""
    if msg is None:
        msg = ("This %(name)s instance is not fitted yet. Call 'fit' first."
               % {'name': type(estimator).__name__})
    if attributes is not None:
        if isinstance(attributes, str):
            attributes = [attributes]
        if not all_or_any([hasattr(estimator, attr) for attr in attributes]):
            raise NotFittedError(msg)
    else:
        fitted_attrs = [a for a in vars(estimator)
                        if a.endswith('_') and not a.startswith('__')]
        if not fitted_attrs:
            raise NotFittedError(msg)


check_is_fitted = check_is_fitted_full


def column_or_1d(y, dtype=None, warn=False):
    """Ravel column or 1d numpy array, else raise an error."""
    y = np.asarray(y, dtype=dtype)
    shape = y.shape
    if len(shape) == 1:
        return y
    if len(shape) == 2 and shape[1] == 1:
        return y.ravel()
    raise ValueError("y should be a 1d array or a column vector, "
                     "got an array of shape %s instead." % str(shape))


def safe_indexing(X, indices):
    """Index arrays or lists safely."""
    if hasattr(X, 'iloc'):
        # pandas-like
        return X.iloc[indices]
    X = np.asarray(X)
    return X[indices]


def indexable(*iterables):
    """Check that all iterables are indexable (have __getitem__ or are None).

    Returns the inputs as-is if valid, converting lists to arrays where needed.
    """
    result = []
    for x in iterables:
        if x is None:
            result.append(x)
        elif hasattr(x, '__getitem__') or hasattr(x, 'iloc'):
            result.append(x)
        else:
            result.append(np.array(list(x)))
    return result
